lessons.concept:
CritBit trees are a type of binary search tree that store strings and are optimized for fast search, insertion, and deletion. Unlike other binary search trees, CritBit trees use a single bit in the strings to determine the branching path. This makes them particularly efficient for string-based data. Here's a simple example of how you might implement a CritBitTree in Nim:

```nim
type
  CritBitNode = ref object
    bitIndex: int
    left, right: CritBitNode
    value: string

proc insert(node: var CritBitNode, value: string) =
  if node == nil:
    node = CritBitNode(bitIndex: -1, value: value)
    return

  if value == node.value:
    return

  let diffIndex = findFirstDiffIndex(value, node.value)
  if diffIndex == -1:
    if value < node.value:
      insert(node.left, value)
    else:
      insert(node.right, value)
  else:
    let newNode = CritBitNode(bitIndex: diffIndex, value: node.value)
    newNode.left = node
    newNode.right = nil
    node = newNode
    insert(node, value)

proc search(node: CritBitNode, value: string): bool =
  if node == nil:
    return false
  if value == node.value:
    return true
  if value[node.bitIndex] == '0':
    return search(node.left, value)
  else:
    return search(node.right, value)

proc findFirstDiffIndex(a, b: string): int =
  for i in 0..min(len(a), len(b)) - 1:
    if a[i] != b[i]:
      return i
  return -1

var root: CritBitNode = nil
insert(root, "apple")
insert(root, "banana")
insert(root, "cherry")

echo search(root, "banana")  # true
echo search(root, "orange")  # false
```

This code defines a simple CritBitTree with insertion and search operations. The `insert` procedure adds a new string to the tree, and the `search` procedure checks if a string is present in the tree.

