lessons.concept:
PEG (Parsing Expression Grammar) is a way to define parsers in a concise and readable manner. In Nim, you can use the `peg` module to define and parse expressions. The key idea is to define rules for parsing and then use actions to capture and process the parsed data. For example, to parse an arithmetic expression like '3 + 5 * 2', you can define rules for numbers and operators, and then use actions to evaluate the expression. Here's a simple example of how you might define such a parser in Nim:

```nim
import peg

let grammar = peg.newGrammar(
  "expr": "term (('+' / '-') term)*",
  "term": "factor (('*' / '/') factor)*",
  "factor": "number / '(' expr ')'"
)

let actions = peg.newActions(
  "expr": proc(nodes: seq[peg.Node]): int =
    let result = nodes[0].value
    for i in countup(1, nodes.len - 1, 2):
      let op = nodes[i].value
      let next = nodes[i + 1].value
      if op == '+':
        result += next
      else:
        result -= next
    return result,
  "term": proc(nodes: seq[peg.Node]): int =
    let result = nodes[0].value
    for i in countup(1, nodes.len - 1, 2):
      let op = nodes[i].value
      let next = nodes[i + 1].value
      if op == '*':
        result *= next
      else:
        result /= next
    return result,
  "factor": proc(nodes: seq[peg.Node]): int =
    if nodes[0].kind == peg.terminal:
      return parseInt(nodes[0].value)
    else:
      return nodes[1].value
)

let parser = peg.newParser(grammar, actions)

let input = "3 + 5 * 2"
let result = parser.parse(input)

if result.isOk:
  echo result.value
else:
  echo "Parse error"
```

In this example, the grammar defines rules for expressions, terms, and factors. The actions define how to evaluate these rules. The `expr` action handles addition and subtraction, the `term` action handles multiplication and division, and the `factor` action handles numbers and parenthesized expressions. When you run this code with the input '3 + 5 * 2', it should output '13'.

